<template>
  <div class="w-full px-4 py-2 border-b hover:bg-lightest transition-colors duration-150 flex flex-row">
    <div class="flex-none">
      <a @click="pushToProfilePage(user.id)">
        <img
          :src="`${user.avatar || '/default_profile.png'}`"
          class="h-12 w-12 rounded-full cursor-pointer transition-opacity duration-150 hover:opacity-80"
         />
      </a>
    </div>
    <div class="ml-2 flex flex-col w-full">
      <div class="flex flex-row justify-between w-full">
        <div class="flex flex-col">

          <p v-if="!user.moderation || user.moderation.is_ok">
            <p class="font-bold">{{ user.username }}</p>
          </p>
          <p v-else>
            <p class="font-bold">Moderated</p>
          </p>
          <p class="text-dark text-sm">@{{ user.id }}</p>
        </div>
        <div v-if="profile && profile.user_id !== user.id" class="relative flex items-center">
          <button
            v-if="!isFollowing()"
            @click="follow"
            class="ml-auto text-blue font-bold px-4 py-1 rounded-full border border-blue mb-2 hover:bg-lightblue"
          >
            Follow
          </button>
          <button
            v-if="isFollowing()"
            @mouseover="followingLabel = 'Unfollow'"
            @mouseleave="followingLabel = 'Following'"
            @click="unfollow"
            class="ml-auto text-white bg-blue font-bold px-4 py-1 rounded-full border mb-2 hover:bg-red-700"
          >
            {{ followingLabel }}
          </button>
          <button
            type="button"
            @click="showMenu = !showMenu"
            class="ml-2 mb-2 rounded-full w-8 h-8 flex items-center justify-center hover:bg-lighter flat-btn"
            :aria-expanded="showMenu"
            aria-label="More options"
          >
            <i class="fas fa-ellipsis-h text-dark text-sm" aria-hidden="true"></i>
          </button>
          <div v-if="showMenu" class="absolute right-0 top-10 mt-1 w-44 bg-white rounded-md shadow-lg py-1 z-10">
            <button type="button" @click="toggleMute" class="block w-full text-left px-4 py-2 text-sm hover:bg-gray-100 flat-btn">{{ isMuted ? `Unmute @${user.id}` : `Mute @${user.id}` }}</button>
            <button
              type="button"
              @click="askBlockToggle"
              class="block w-full text-left px-4 py-2 text-sm hover:bg-gray-100 flat-btn"
              :class="isBlocked ? 'text-blue' : 'text-red-600'"
            >{{ isBlocked ? `Unblock @${user.id}` : `Block @${user.id}` }}</button>
          </div>
        </div>
      </div>
      <div>
        <p v-if="!user.moderation || user.moderation.is_ok">
          {{ user.bio }}
        </p>
        <p v-else class="pb-2 bg-red-300">
          Moderated: {{ user.moderation.reason }}
        </p>
      </div>
    </div>
    <ConfirmDialog
      :show="showBlockConfirm"
      :title="isBlocked ? 'Unblock user' : 'Block user'"
      :message="isBlocked
        ? `Unblock @${user.id}? They'll be able to follow you and see your tweets again.`
        : `Block @${user.id}? They'll no longer be able to follow you or see your tweets.`"
      :confirm-label="isBlocked ? 'Unblock' : 'Block'"
      :destructive="!isBlocked"
      @cancel="showBlockConfirm = false"
      @confirm="onBlockConfirmed"
    />
  </div>
</template>

<script>
import {defineAsyncComponent} from "vue";
import {warpnetService} from "@/service/service";

export default {
  name: "User",
  props: {
    user: {
      id: "",
      username: "",
      type: Object,
      required: true,
      avatar: "",
      following: false,
    }
  },
  components: {
    ConfirmDialog: defineAsyncComponent(() => import('./ConfirmDialog.vue')),
  },
  data() {
    return {
      followingLabel: "Following",
      profile: {},
      followingStatus: new Map(),
      showMenu: false,
      isBlocked: false,
      isMuted: false,
      showBlockConfirm: false,
    };
  },
  methods: {
    isFollowing() {
      return this.followingStatus.get(this.user.id) || false
    },
    async follow() {
      try {
        await warpnetService.followUser(this.user.id);
      } catch (err) {
        console.error(`failed to follow [${this.user.id}]`, err);
        return
      }
      this.followingStatus.set(this.user.id, true);
    },
    async unfollow() {
      try {
        await warpnetService.unfollowUser(this.user.id);
      } catch (err) {
        console.error(`failed to unfollow [${this.user.id}]`, err);
        return
      }
      this.followingStatus.set(this.user.id, false);
    },
    async toggleMute() {
      this.showMenu = false;
      try {
        if (this.isMuted) {
          await warpnetService.unmuteUser(this.user.id);
          this.isMuted = false;
        } else {
          await warpnetService.muteUser(this.user.id);
          this.isMuted = true;
        }
      } catch (err) {
        console.error(`failed to toggle mute on [${this.user.id}]`, err);
      }
    },
    askBlockToggle() {
      this.showMenu = false;
      this.showBlockConfirm = true;
    },
    async onBlockConfirmed() {
      this.showBlockConfirm = false;
      try {
        if (this.isBlocked) {
          await warpnetService.unblockUser(this.user.id);
          this.isBlocked = false;
        } else {
          await warpnetService.blockUser(this.user.id);
          this.isBlocked = true;
        }
      } catch (err) {
        console.error(`failed to toggle block on [${this.user.id}]`, err);
      }
    },
    async pushToProfilePage(profileId) {
      this.$router.push({
        name: "Profile",
        params: {
          id: profileId
        }
      });
    },
  },
  async created() {
    console.log("loading component:", this.$options.name);
    this.profile = warpnetService.getOwnerProfile();
    this.user.avatar = await warpnetService.getImage({userId:this.user.id, key:this.user.avatar_key})

    const status = await warpnetService.isFollowing(this.user.id);
    this.followingStatus.set(this.user.id, status);

    try {
      this.isBlocked = await warpnetService.isUserBlocked(this.user.id);
    } catch (err) {
      console.warn(`failed to read block state for [${this.user.id}]:`, err);
    }

    try {
      this.isMuted = await warpnetService.isUserMuted(this.user.id);
    } catch (err) {
      console.warn(`failed to read mute state for [${this.user.id}]:`, err);
    }
  },
};
</script>
